SELECT total_cases
FROM countries
WHERE country_id = 1;

SELECT country_name, recovery_rate AS recovery_percentage
FROM countries
ORDER BY recovery_rate DESC;

SELECT vd.total_vaccinated, c.total_hospitalized
FROM vaccination_data vd
JOIN countries c ON vd.country_id = c.country_id
WHERE c.population = (
  SELECT MAX(population) FROM countries
);
